#include <stdio.h>
#include <stdint.h>

// Simulating the buggy function
int buggy_wicompare(const uint8_t* data, size_t data_size, uint8_t* string, size_t string_length)
{
  const uint8_t* s1 = data;
  const uint8_t* s2 = string;
  size_t i = 0;

  if (data_size < string_length * 2)
    return 0;

  // Simplified: just compare bytes directly (no lowercase table)
  while (i < string_length && *s1 == *s2)
  {
    s1+=2;
    s2++;
    i++;
  }

  return (int) ((i == string_length) ? i * 2 : 0);
}

int main() {
  uint8_t data[] = {0x20, 0xF7, 0x63, 0x00, 0x6D, 0x00};  // \uf720 c m
  uint8_t pattern[] = {0x20, 0x63, 0x6D};  // " c m"

  int result = buggy_wicompare(data, sizeof(data), pattern, sizeof(pattern));
  printf("Result: %d (should be 0, but buggy code returns %d)\n", result, result);

  return 0;
}
EOF
