#include <stdio.h>
#include <stdint.h>

// Fixed version
int fixed_wicompare(const uint8_t* data, size_t data_size, uint8_t* string, size_t string_length)
{
  const uint8_t* s1 = data;
  const uint8_t* s2 = string;
  size_t i = 0;

  if (data_size < string_length * 2)
    return 0;

  // Fixed: also check that high byte is 0x00
  while (i < string_length && *s1 == *s2 && *(s1 + 1) == 0x00)
  {
    s1+=2;
    s2++;
    i++;
  }

  return (int) ((i == string_length) ? i * 2 : 0);
}

int main() {
  uint8_t data[] = {0x20, 0xF7, 0x63, 0x00, 0x6D, 0x00};  // \uf720 c m
  uint8_t pattern[] = {0x20, 0x63, 0x6D};  // " c m"

  int result = fixed_wicompare(data, sizeof(data), pattern, sizeof(pattern));
  printf("Result: %d (correctly returns 0 - no match)\n", result);

  // Test with correct data
  uint8_t data2[] = {0x20, 0x00, 0x63, 0x00, 0x6D, 0x00};  // " c m" in wide
  result = fixed_wicompare(data2, sizeof(data2), pattern, sizeof(pattern));
  printf("Result with correct data: %d (correctly returns 6 - match)\n", result);

  return 0;
}
EOF
